// Generate mock AI metrics data for multiple inference endpoints
const endpoints = [
  { name: 'gpt-4-turbo', provider: 'OpenAI', costPerToken: 0.00003 },
  { name: 'claude-3-opus', provider: 'Anthropic', costPerToken: 0.000015 },
  { name: 'claude-3-sonnet', provider: 'Anthropic', costPerToken: 0.000003 },
  { name: 'gpt-3.5-turbo', provider: 'OpenAI', costPerToken: 0.0000015 },
  { name: 'llama-2-70b', provider: 'Meta', costPerToken: 0.000001 }
];

const mockData = [];
const now = new Date();

// Generate data for the last 24 hours with hourly intervals
for (let i = 0; i < 24; i++) {
  const timestamp = new Date(now.getTime() - (i * 60 * 60 * 1000));

  endpoints.forEach(endpoint => {
    // Generate random metrics
    const inputTokens = Math.floor(Math.random() * 5000) + 500;
    const outputTokens = Math.floor(Math.random() * 2000) + 200;
    const totalTokens = inputTokens + outputTokens;
    const requestCount = Math.floor(Math.random() * 100) + 10;
    const latencyMs = Math.floor(Math.random() * 3000) + 200;
    const errorRate = Math.random() * 0.05; // 0-5% error rate
    const cost = totalTokens * endpoint.costPerToken * requestCount;

    mockData.push({
      timestamp: timestamp.toISOString(),
      modelName: endpoint.name,
      provider: endpoint.provider,
      inputTokens: inputTokens,
      outputTokens: outputTokens,
      totalTokens: totalTokens,
      requestCount: requestCount,
      latencyMs: latencyMs,
      errorRate: parseFloat(errorRate.toFixed(4)),
      costPerToken: endpoint.costPerToken,
      totalCost: parseFloat(cost.toFixed(4)),
      avgTokensPerRequest: Math.floor(totalTokens / requestCount),
      throughput: parseFloat((requestCount / 3600).toFixed(2)), // requests per second
      cacheHitRate: parseFloat((Math.random() * 0.3).toFixed(2)) // 0-30% cache hit rate
    });
  });
}

// Calculate summary statistics
const totalCost = mockData.reduce((sum, item) => sum + item.totalCost, 0);
const totalRequests = mockData.reduce((sum, item) => sum + item.requestCount, 0);
const avgLatency = mockData.reduce((sum, item) => sum + item.latencyMs, 0) / mockData.length;

return [
  {
    json: {
      metrics: mockData,
      summary: {
        totalCost: parseFloat(totalCost.toFixed(2)),
        totalRequests: totalRequests,
        avgLatency: parseFloat(avgLatency.toFixed(2)),
        timeRange: '24h',
        endpointCount: endpoints.length,
        generatedAt: now.toISOString()
      }
    }
  }
];

