// Check if current costs exceed budget thresholds
// Access workflow configuration and cost data from previous nodes
const workflowConfig = $('Workflow Configuration').item.json;
const costData = $('Cost Intelligence Agent').item.json;

// Extract budget threshold and current costs
const budgetThreshold = workflowConfig.budgetThreshold || 1000;
const currentCosts = costData.totalCost || 0;

// Calculate budget metrics
const remainingBudget = budgetThreshold - currentCosts;
const percentUsed = (currentCosts / budgetThreshold) * 100;
const exceeded = currentCosts > budgetThreshold;

// Return budget status
const status = {
  exceeded: exceeded,
  remainingBudget: remainingBudget.toFixed(2),
  percentUsed: percentUsed.toFixed(2),
  currentCosts: currentCosts.toFixed(2),
  budgetThreshold: budgetThreshold.toFixed(2),
  status: exceeded ? 'OVER BUDGET' : (percentUsed > 80 ? 'WARNING' : 'OK')
};

return JSON.stringify(status);

// Analyze cost per model and latency to recommend routing optimizations
// Input: query should contain cost and performance metrics

// Parse the query to extract metrics (assuming JSON format)
let metrics;
try {
  metrics = typeof query === 'string' ? JSON.parse(query) : query;
} catch (e) {
  return 'Error: Invalid input format. Please provide cost and performance metrics in JSON format.';
}

// Extract model metrics
const models = metrics.models || [];

if (models.length === 0) {
  return 'No model data available for analysis.';
}

// Analyze each model's cost-effectiveness
const analysis = models.map(model => {
  const costPerRequest = model.totalCost / model.requestCount;
  const avgLatency = model.avgLatency || 0;

  return {
    modelName: model.name,
    costPerRequest: costPerRequest,
    avgLatency: avgLatency,
    requestCount: model.requestCount,
    costEfficiencyScore: avgLatency > 0 ? (1 / costPerRequest) * (1000 / avgLatency) : 0
  };
});

// Sort by cost efficiency
analysis.sort((a, b) => b.costEfficiencyScore - a.costEfficiencyScore);

// Generate recommendations
const recommendations = [];

const mostExpensive = analysis.reduce((max, m) => m.costPerRequest > max.costPerRequest ? m : max, analysis[0]);
const cheapest = analysis.reduce((min, m) => m.costPerRequest < min.costPerRequest ? m : min, analysis[0]);
const fastest = analysis.reduce((min, m) => m.avgLatency < min.avgLatency ? m : min, analysis[0]);

// Recommendation 1: Route non-critical workloads to cheaper models
if (mostExpensive.costPerRequest > cheapest.costPerRequest * 2) {
  recommendations.push({
    type: 'cost_optimization',
    priority: 'high',
    recommendation: `Switch non-critical workloads from ${mostExpensive.modelName} to ${cheapest.modelName}`,
    potentialSavings: `${((mostExpensive.costPerRequest - cheapest.costPerRequest) / mostExpensive.costPerRequest * 100).toFixed(1)}% cost reduction`,
    details: `${mostExpensive.modelName} costs $${mostExpensive.costPerRequest.toFixed(4)} per request vs ${cheapest.modelName} at $${cheapest.costPerRequest.toFixed(4)}`
  });
}

// Recommendation 2: Balance latency and cost
analysis.forEach(model => {
  if (model.avgLatency > fastest.avgLatency * 2 && model.costPerRequest > cheapest.costPerRequest * 1.5) {
    recommendations.push({
      type: 'performance_cost_balance',
      priority: 'medium',
      recommendation: `Consider replacing ${model.modelName} - high latency and high cost`,
      details: `Latency: ${model.avgLatency}ms, Cost: $${model.costPerRequest.toFixed(4)} per request`
    });
  }
});

// Recommendation 3: Optimize high-volume routes
const highVolumeModels = analysis.filter(m => m.requestCount > (metrics.totalRequests || 0) * 0.3);
highVolumeModels.forEach(model => {
  if (model.costPerRequest > cheapest.costPerRequest * 1.3) {
    recommendations.push({
      type: 'high_volume_optimization',
      priority: 'high',
      recommendation: `Optimize ${model.modelName} routing - high volume with above-average cost`,
      potentialSavings: `Estimated ${((model.costPerRequest - cheapest.costPerRequest) * model.requestCount).toFixed(2)} in savings`,
      details: `${model.requestCount} requests at $${model.costPerRequest.toFixed(4)} per request`
    });
  }
});

// Format output
const output = {
  summary: `Analyzed ${models.length} models, generated ${recommendations.length} recommendations`,
  mostCostEffective: cheapest.modelName,
  fastestModel: fastest.modelName,
  recommendations: recommendations,
  modelAnalysis: analysis
};

return JSON.stringify(output, null, 2);

